<script>
document.addEventListener('DOMContentLoaded', function() {
    const toggleBtn = document.getElementById('riskDisclaimerToggle');
    const content = document.getElementById('riskDisclaimerContent');
    const chevron = document.getElementById('disclaimerChevron');

    if (toggleBtn && content) {
        toggleBtn.addEventListener('click', function() {
            const isOpen = content.style.display !== 'none';
            content.style.display = isOpen ? 'none' : 'block';
            if (chevron) {
                chevron.style.transform = isOpen ? 'rotate(0deg)' : 'rotate(180deg)';
            }
        });
    }

    // Hover effects for link indicators
    document.querySelectorAll('.footer-grid a').forEach(function(link) {
        link.addEventListener('mouseenter', function() {
            const indicator = this.querySelector('.link-indicator');
            if (indicator) indicator.style.width = '8px';
        });
        link.addEventListener('mouseleave', function() {
            const indicator = this.querySelector('.link-indicator');
            if (indicator) indicator.style.width = '0';
        });
    });
});
</script>
